	}
	if len(cc.CapDrop) != 1 || cc.CapDrop[0] != "MKNOD" {
		t.Errorf("CapDrop = %v, want [MKNOD]", cc.CapDrop)
	}
	if len(cc.Devices) != 1 || cc.Devices[0] != "/dev/fuse" {
		t.Errorf("Devices = %v, want [/dev/fuse]", cc.Devices)
	}
	if cc.Labels["env"] != "test" {
