		{"/dev/fuse:/dev/fuse", "/dev/fuse", "/dev/fuse", "rwm"},
		{"/dev/sda:/dev/xvda:r", "/dev/sda", "/dev/xvda", "r"},
	}
	for _, tt := range tests {
