		Volumes: []string{
			"/host/data:/container/data",
			"/host/config:/container/config:ro",
		},
	})

	if _, _, err := d.StartTask(cfg); err != nil {
		t.Fatalf("StartTask: %v", err)
	}

	cc := rec.lastConfig()
	if cc == nil {
