func TestParseDevice(t *testing.T) {
	tests := []struct {
		input     string
		wantHost  string
		wantCtr   string
		wantPerms string
	}{
		{"/dev/fuse", "/dev/fuse", "", "rwm"},
		{"/dev/fuse:/dev/fuse", "/dev/fuse", "/dev/fuse", "rwm"},
		{"/dev/sda:/dev/xvda:r", "/dev/sda", "/dev/xvda", "r"},
	}
	for _, tt := range tests {
		t.Run(tt.input, func(t *testing.T) {
