	if err != nil {
		t.Fatalf("credential lookup: %v", err)
	}
	if user != "homeuser" || pass != "homepass" {
		t.Errorf("got (%q, %q), want (\"homeuser\", \"homepass\")", user, pass)
	}
}

func TestDockerCredentialFuncUserHomeError(t *testing.T) {
