	// Channel should close after cancellation.
	select {
	case _, ok := <-ch:
		if ok {
			t.Fatal("expected closed channel after context cancellation")
		}
	case <-time.After(2 * time.Second):
		t.Fatal("channel not closed after cancel within timeout")
	}
}

